<script lang="ts">import FieldRoot from'@fex/components-svelte/primitive/field';import Field from'@fex/components-svelte/primitive/form-field';import FieldControl from'@fex/components-svelte/primitive/field-control';import FieldError from'@fex/components-svelte/primitive/field-error';import FieldLabel from'@fex/components-svelte/primitive/field-label';import Form from'@fex/components-svelte/primitive/form';import{createForm}from'@fex/components-svelte/primitive/form/create-form';import SelectRoot from'@fex/components-svelte/primitive/select';import SelectContent from'@fex/components-svelte/primitive/select-content';import SelectTrigger from'@fex/components-svelte/primitive/select-trigger';import Button from'@fex/components-svelte/ui/button';import{frameworkOptions}from'./data';import Demo from'./demo-section.svelte';const form=createForm(()=>({defaultValues:{framework:''},onSubmit:()=>undefined}))</script><Demo title="Form validation" description="Submit the real form without a value to produce Select error state."><Form {form} class="space-y-space-md"><Field name="framework" validators={{onSubmit:({value}:{value:string})=>value?undefined:'Please select a framework'}}>{#snippet children(field)}{@const errors=field.state.meta.errors.map(String)}{@const invalid=errors.length>0}<FieldRoot {invalid} hasError={invalid}><FieldLabel>Framework</FieldLabel><FieldControl>{#snippet children(binding)}<SelectRoot value={field.state.value} status={invalid?'error':undefined} options={frameworkOptions} onChange={value=>field.handleChange(String(value??''))}><SelectTrigger {...binding.props} placeholder="请选择"/><SelectContent/></SelectRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Button type="submit">Validate</Button></Form></Demo>
